"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["362"],{1254(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"dawn","metadata":{"permalink":"/lattice/gallery/dawn","source":"@site/blog/2021-08-26-welcome/index.mdx","title":"Guiding Personal AI Agents with Insights","description":"Docusaurus blogging features are powered by the blog plugin.","date":"2021-08-26T00:00:00.000Z","tags":[],"readingTime":0.56,"hasTruncateMarker":true,"authors":[{"name":"Dora Zhao","title":"PhD Student, Stanford HCI","url":"https://dorazhao99.github.io/","page":{"permalink":"/lattice/gallery/authors/dorazhao"},"socials":{"x":"https://x.com/dorazhao9"},"imageURL":"https://github.com/yangshun.png","key":"dorazhao"}],"frontMatter":{"slug":"dawn","title":"Guiding Personal AI Agents with Insights","authors":"dorazhao"},"unlisted":false},"content":"[Docusaurus blogging features](https://docusaurus.io/docs/blog) are powered by the [blog plugin](https://docusaurus.io/docs/api/plugins/@docusaurus/plugin-content-blog).\\n\\nHere are a few tips you might find useful.\\n\\n{/* truncate */}\\n\\nSimply add Markdown files (or folders) to the `blog` directory.\\n\\nRegular blog authors can be added to `authors.yml`.\\n\\nThe blog post date can be extracted from filenames, such as:\\n\\n- `2019-05-30-welcome.md`\\n- `2019-05-30-welcome/index.md`\\n\\nA blog post folder can be convenient to co-locate blog post images:\\n\\n![Docusaurus Plushie](./docusaurus-plushie-banner.jpeg)\\n\\nThe blog supports tags as well!\\n\\n**And if you don\'t want a blog**: just delete this directory, and use `blog: false` in your Docusaurus config."}]}}')}}]);